import React, { useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { LogOut, User, Calendar, Home } from 'lucide-react';

const Navbar = () => {
    const { user, logout } = useContext(AuthContext);
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    return (
        <nav className="bg-white shadow-sm border-b px-6 py-4 flex justify-between items-center">
            <Link to="/" className="text-xl font-bold text-blue-600 flex items-center gap-2">
                <Home size={24} /> MockInterviews
            </Link>

            <div className="flex items-center gap-6">
                {!user ? (
                    <>
                        <Link to="/login" className="text-gray-600 hover:text-blue-600">Login</Link>
                        <Link to="/register" className="bg-blue-600 text-white px-4 py-2 rounded-md hover:bg-blue-700">
                            Get Started
                        </Link>
                    </>
                ) : (
                    <>
                        {/* Interviewer Links */}
                        {user.role === 'ROLE_INTERVIEWER' && (
                            <Link to="/interviewer/availability" className="flex items-center gap-1 text-gray-600 hover:text-blue-600">
                                <Calendar size={18} /> Availability
                            </Link>
                        )}

                        {/* Candidate Links */}
                        {user.role === 'ROLE_CANDIDATE' && (
                            <Link to="/candidate/search" className="text-gray-600 hover:text-blue-600">
                                Find Interviewers
                            </Link>
                        )}

                        <div className="flex items-center gap-4 border-l pl-6">
                            <span className="text-sm font-medium text-gray-700 flex items-center gap-1">
                                <User size={18} /> {user.sub}
                            </span>
                            <button 
                                onClick={handleLogout}
                                className="text-red-500 hover:text-red-700 flex items-center gap-1"
                            >
                                <LogOut size={18} /> Logout
                            </button>
                        </div>
                    </>
                )}
            </div>
        </nav>
    );
};

export default Navbar;
